import React, { useState, useEffect, useRef } from 'react';
import { Button, Box, TextField, Collapse } from '@mui/material';

function AutoFocusForm() {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const inputRef = useRef(null);

  useEffect(() => {
    // Nếu form được mở và ref đã tồn tại
    if (isFormOpen && inputRef.current) {
      // Focus vào element
      inputRef.current.focus();
    }
  }, [isFormOpen]); // Phụ thuộc vào trạng thái isFormOpen

  return (
    <Box sx={{ minWidth: '250px' }}>
      <Collapse in={!isFormOpen}>
        <Button onClick={() => setIsFormOpen(true)} variant="contained">Thêm mới</Button>
      </Collapse>
      <Collapse in={isFormOpen}>
        <Box sx={{ p: 2, border: '1px dashed grey', borderRadius: '4px' }}>
          <TextField 
            inputRef={inputRef} 
            fullWidth
            placeholder="Nhập tiêu đề..."
          />
          <Button sx={{ mt: 1 }} onClick={() => setIsFormOpen(false)}>Hủy</Button>
        </Box>
      </Collapse>
    </Box>
  );
}

export default AutoFocusForm;

