import React, { useState, useEffect, useRef } from 'react';
import { Button, Box, TextField, Collapse } from '@mui/material';

function AddNewItem({ type }) {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [title, setTitle] = useState('');
  const inputRef = useRef(null);

  const buttonText = type === 'Column' ? '+ Thêm cột khác' : '+ Thêm thẻ';
  const placeholderText = type === 'Column' ? 'Nhập tiêu đề cột...' : 'Nhập tiêu đề thẻ...';
  const addButtonText = type === 'Column' ? 'Thêm Cột' : 'Thêm Thẻ';

  useEffect(() => {
    if (isFormOpen) {
      inputRef.current?.focus();
    }
  }, [isFormOpen]);

  const handleAdd = () => {
    if (title.trim()) {
      console.log(`New ${type}: ${title}`);
      setTitle('');
      setIsFormOpen(false);
    }
  };

  const handleCancel = () => {
    setTitle('');
    setIsFormOpen(false);
  };

  return (
    <Box sx={{ minWidth: '272px', p: 1 }}>
      <Collapse in={!isFormOpen}>
        <Button 
          fullWidth
          variant="text" 
          onClick={() => setIsFormOpen(true)}
          sx={{ justifyContent: 'flex-start' }}
        >
          {buttonText}
        </Button>
      </Collapse>
      <Collapse in={isFormOpen}>
        <Box sx={{ p: 1, bgcolor: '#ffffff', borderRadius: '4px' }}>
          <TextField 
            fullWidth
            inputRef={inputRef}
            placeholder={placeholderText}
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAdd()}
          />
          <Box sx={{ mt: 1, display: 'flex', gap: 1 }}>
            <Button onClick={handleAdd} variant="contained">{addButtonText}</Button>
            <Button onClick={handleCancel} variant="text" color="error">Hủy</Button>
          </Box>
        </Box>
      </Collapse>
    </Box>
  );
}

export default AddNewItem;
